import{_ as t,c as o,o as a,ag as r}from"./chunks/framework.Dj4VfQLU.js";const g=JSON.parse('{"title":"HTTPS & SSL setup","description":"","frontmatter":{"icon":"shield"},"headers":[],"relativePath":"https-and-ssl-setup.md","filePath":"https-and-ssl-setup.md"}'),s={name:"https-and-ssl-setup.md"};function n(i,e,l,d,c,p){return a(),o("div",null,e[0]||(e[0]=[r('<h1 id="https-ssl-setup" tabindex="-1">HTTPS &amp; SSL setup <a class="header-anchor" href="#https-ssl-setup" aria-label="Permalink to &quot;HTTPS &amp; SSL setup&quot;">​</a></h1><p>Proper SSL configuration is essential for securing your BetterTaxi instance, ensuring data encryption, and enabling features like Firebase push notifications and secure payment gateways.</p><p>BetterTaxi supports both <strong>Cloudflare-based flexible SSL</strong> and <strong>manual certificate installation</strong>. Cloudflare is the <strong>recommended and simplest approach</strong>.</p><hr><h4 id="🌐-recommended-setup-cloudflare-flexible-ssl" tabindex="-1">🌐 Recommended Setup: Cloudflare Flexible SSL <a class="header-anchor" href="#🌐-recommended-setup-cloudflare-flexible-ssl" aria-label="Permalink to &quot;🌐 Recommended Setup: Cloudflare Flexible SSL&quot;">​</a></h4><p>We recommend using <a href="https://cloudflare.com/" target="_blank" rel="noreferrer"><strong>Cloudflare</strong></a> as your DNS and SSL provider. It simplifies the process and works seamlessly with the default Docker configuration.</p><p><strong>✅ Requirements</strong></p><ul><li>A <strong>static IP address</strong> (required for license validation)</li><li>A registered domain name (e.g., <code>yourdomain.com</code>)</li><li>Access to your domain&#39;s DNS management</li></ul><hr><h4 id="⚙️-step-by-step-setup-with-cloudflare" tabindex="-1">⚙️ Step-by-Step Setup with Cloudflare <a class="header-anchor" href="#⚙️-step-by-step-setup-with-cloudflare" aria-label="Permalink to &quot;⚙️ Step-by-Step Setup with Cloudflare&quot;">​</a></h4><ol><li><strong>Point Your Domain to the Server</strong><ul><li><p>Set an <code>A</code> record in your Cloudflare DNS settings:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>yourdomain.com → &lt;your-static-ip&gt;</span></span></code></pre></div></li></ul></li><li><strong>Enable Cloudflare SSL</strong><ul><li>Go to:<br><code>Cloudflare Dashboard → SSL/TLS → Overview</code></li><li>Select <strong>Flexible</strong> SSL mode (Cloudflare communicates with server over HTTP)</li></ul></li><li><strong>Optional: Enable Always Use HTTPS</strong><ul><li><p>This ensures all HTTP traffic is automatically redirected to HTTPS:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cloudflare → SSL/TLS → Edge Certificates → Always Use HTTPS → ON</span></span></code></pre></div></li></ul></li><li><strong>DNS Propagation</strong><ul><li>Wait up to 5 minutes for DNS changes to take effect</li></ul></li></ol><blockquote><p>🚀 Once this is done, your app will be available at:</p></blockquote><ul><li><code>https://yourdomain.com/admin/</code> (Admin Panel)</li><li><code>https://yourdomain.com/booking/</code> (Customer Web App)</li></ul><hr><h4 id="🛠️-advanced-option-manual-ssl-with-let-s-encrypt" tabindex="-1">🛠️ Advanced Option: Manual SSL with Let&#39;s Encrypt <a class="header-anchor" href="#🛠️-advanced-option-manual-ssl-with-let-s-encrypt" aria-label="Permalink to &quot;🛠️ Advanced Option: Manual SSL with Let&#39;s Encrypt&quot;">​</a></h4><p>If you prefer <strong>manual SSL management</strong>, you can install <strong>Let&#39;s Encrypt</strong> certificates using external tools like:</p><ul><li><a href="https://certbot.eff.org/" target="_blank" rel="noreferrer"><code>certbot</code></a></li><li><a href="https://nginxproxymanager.com/" target="_blank" rel="noreferrer"><code>nginx-proxy-manager</code></a></li><li>Dockerized SSL companions like <code>nginx-certbot</code></li></ul><p>However, this route requires:</p><ul><li>Exposing port 443</li><li>Customizing NGINX or reverse proxy configurations</li><li>Setting up renewal scripts or cron jobs</li></ul><p>This option is only recommended for experienced users or those integrating into an existing DevOps pipeline.</p><hr><h4 id="⚠️-notes-considerations" tabindex="-1">⚠️ Notes &amp; Considerations <a class="header-anchor" href="#⚠️-notes-considerations" aria-label="Permalink to &quot;⚠️ Notes &amp; Considerations&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Item</th><th>Detail</th></tr></thead><tbody><tr><td><strong>NGINX Role</strong></td><td>Included in Docker stack, listens on port 80</td></tr><tr><td><strong>No Port 443 Binding Required</strong></td><td>Cloudflare handles SSL offloading</td></tr><tr><td><strong>No Manual NGINX Configuration</strong></td><td>Unless bypassing Cloudflare</td></tr><tr><td><strong>SSL for API &amp; Admin</strong></td><td>Served under path-based routes (e.g., <code>/admin/</code>, <code>/booking/</code>)</td></tr><tr><td><strong>Static IP Requirement</strong></td><td>Enforced solely for <strong>license verification</strong>, not for SSL</td></tr><tr><td><strong>Multiple Services on One Domain</strong></td><td>Supported via path-based routing: <code>yourdomain.com/admin/</code>, etc.</td></tr></tbody></table><hr><h4 id="🔁-testing-ssl" tabindex="-1">🔁 Testing SSL <a class="header-anchor" href="#🔁-testing-ssl" aria-label="Permalink to &quot;🔁 Testing SSL&quot;">​</a></h4><p>You can test if your setup is working using:</p><ul><li><code>https://yourdomain.com/admin/</code> in your browser</li><li><a href="https://www.ssllabs.com/ssltest/" target="_blank" rel="noreferrer">SSL Labs</a> for detailed analysis</li><li>Inspecting response headers for <code>Strict-Transport-Security</code> (if enabled)</li></ul>',27)]))}const h=t(s,[["render",n]]);export{g as __pageData,h as default};
